import{_ as h,g as t,f as a,z as o}from"./chunks/framework.pU9sRy1K.js";const k=JSON.parse('{"title":"Kinh Pháp Cú — Phẩm Song Yếu","description":"20 câu kệ mở đầu nổi tiếng về nhân quả của tâm ý.","frontmatter":{"code":"Pc. 1","title":"Kinh Pháp Cú — Phẩm Song Yếu","pali":"Dhammapada — Yamakavagga","group":"Thi kệ & giáo huấn","translation":"thich-minh-chau","book":"tieu-bo","description":"20 câu kệ mở đầu nổi tiếng về nhân quả của tâm ý."},"headers":[],"relativePath":"kinh/tieu-bo/thich-minh-chau/dhp-1-kinh-phap-cu.md","filePath":"kinh/tieu-bo/thich-minh-chau/dhp-1-kinh-phap-cu.md","lastUpdated":1782983601000}'),i={name:"kinh/tieu-bo/thich-minh-chau/dhp-1-kinh-phap-cu.md"};function c(e,n,p,g,u,m){return t(),a("div",null,[...n[0]||(n[0]=[o('<h2 id="pham-song-yeu-yamakavagga" tabindex="-1">Phẩm Song Yếu (Yamakavagga) <a class="header-anchor" href="#pham-song-yeu-yamakavagga" aria-label="Permalink to “Phẩm Song Yếu (Yamakavagga)”">​</a></h2><p><strong>Kệ 1</strong></p><blockquote><p>Ý dẫn đầu các pháp, ý làm chủ, ý tạo tác. Nếu với ý ô nhiễm, nói năng hay hành động, Khổ não sẽ theo ta, như xe theo chân vật kéo xe.</p></blockquote><p><strong>Kệ 2</strong></p><blockquote><p>Ý dẫn đầu các pháp, ý làm chủ, ý tạo tác. Nếu với ý thanh tịnh, nói năng hay hành động, Hạnh phúc sẽ theo ta, như bóng theo hình.</p></blockquote><p><strong>Kệ 3–4</strong></p><blockquote><p>&quot;Người ấy mắng ta, người kia đánh ta, Kẻ khác hãm hại ta&quot; — ai giữ oán hận như vậy, Oán hận không bao giờ dứt.</p></blockquote><blockquote><p>&quot;Người ấy mắng ta, người kia đánh ta, Kẻ khác hãm hại ta&quot; — ai không giữ oán hận như vậy, Oán hận được dứt.</p></blockquote><p><strong>Kệ 5</strong></p><blockquote><p>Không bao giờ trong đời này hay đời sau, Oán hận được dập tắt bằng oán hận; Chỉ có từ bi mới dập tắt được oán hận. Đây là pháp cổ xưa.</p></blockquote><hr>',11)])])}const s=h(i,[["render",c]]);export{k as __pageData,s as default};
